#include<bits/stdc++.h>
using namespace std;
string a;
int p1, p2, p3;
int main() {
	cin >> p1 >> p2 >> p3;
	cin >> a;
	for (int i = 0; i < a.size(); i++) {
		if (a[i] == '-') {
			if (a[i - 1] >= a[i + 1]||(a[i - 1] >= '0' && a[i - 1] <= '9'&&a[i + 1] >= 'a' && a[i + 1] <= 'z')||i==0||(a[i - 1]=='-'&&a[i + 1] >= 'a' && a[i + 1] <= 'z')||(a[i - 1]=='-'&&a[i + 1] >= '0' && a[i + 1] <= '9')) {
				cout << "-";
			} else {
				if (a[i - 1] >= 'a' && a[i - 1] <= 'z' && a[i + 1] >= 'a' && a[i + 1] <= 'z') {
					if (p3 == 1) {
						if (p1 == 1) {
							for (int j = int(a[i - 1] - 'a')+1; j < char(a[i + 1] - 'a'); j++) {
								for (int k = 1; k <= p2; k++) cout << char(j + 'a');
							}
						} else if (p1 == 2) {
							for (int j = int(a[i - 1] - 'a')+1; j < char(a[i + 1] - 'a'); j++) {
								for (int k = 1; k <= p2; k++) cout << char(j + 'A');
							}
						} else {
							for (int j = int(a[i - 1] - 'a')+1; j < char(a[i + 1] - 'a'); j++) {
								for (int k = 1; k <= p2; k++) cout << '*';
							}
						}
					} else {
						if (p1 == 1) {
							for (int j = char(a[i + 1] - 'a') - 1; j > int(a[i - 1] - 'a'); j--) {
								for (int k = 1; k <= p2; k++) cout << char(j + 'a');
							}
						} else if (p1 == 2) {
							for (int j = char(a[i + 1] - 'a') - 1; j > int(a[i - 1] - 'a'); j--) {
								for (int k = 1; k <= p2; k++) cout << char(j + 'A');
							}
						} else {
							for (int j = char(a[i + 1] - 'a') - 1; j > int(a[i - 1] - 'a'); j--) {
								for (int k = 1; k <= p2; k++) cout << '*';
							}
						}
					}
				} else {

					if (p3 == 1) {
						if (p1 == 3) {
							cout << "1";
							for (int j = int(a[i - 1] - '0')+ 1; j < char(a[i + 1] - '0'); j++) {
								for (int k = 1; k <= p2; k++) cout << '*';
							}
						} else{
							for (int j = int(a[i - 1] - '0') +1; j < char(a[i + 1] - '0'); j++) {
								for (int k = 1; k <= p2; k++) cout << char(j + '0');
							}
						}

					} else {
						if (p1 == 3) {
							for (int j = char(a[i + 1] - '0') -1; j > int(a[i - 1] - '0'); j--) {
								for (int k = 1; k <= p2; k++) cout << '*';
							}

						} else {
							for (int j = char(a[i + 1] - '0') - 1; j > int(a[i - 1] - '0'); j--) {
								for (int k = 1; k <= p2; k++) cout << char(j + '0');
							}
						}
					}
				}
			}
		} else {
			cout << a[i];
		}
	}
	return 0;
}
